// scripts/data/denial-codes-seed.ts
// Static CARC denial code seed data.
// Source: X12 CARC (Claim Adjustment Reason Codes) — https://x12.org/codes/claim-adjustment-reason-codes
// Tier A (~50): fully enriched — review_status: 'draft' (Kate review required before 'approved').
// Tier B (~220): explanation + action only — review_status: 'needs_review'.
// NO AI GENERATION — all content is static. (MA-SEC-002 + CLAUDE.md)

type DenialCodeCategory =
  | 'labs' | 'imaging' | 'surgery' | 'dme' | 'pharmacy'
  | 'mental_health' | 'prior_auth' | 'coordination' | 'timely_filing' | 'other'
  | 'medical_necessity' | 'coverage' | 'billing_error'

type ToolCtaId = 'denial_decoder' | 'appeal_generator' | 'bill_dispute' | 'hipaa_request'

interface DenialCodeSeedRecord {
  code:                       string
  category:                   DenialCodeCategory
  plain_language_explanation: string
  recommended_action:         string
  source:                     string
  common_causes:              string | null
  appeal_angle:               string | null
  related_codes:              string[] | null
  tool_cta_id:                ToolCtaId | null
  // Intentionally narrower than DenialCode.review_status — seed records may only be 'draft' or 'needs_review'
  review_status:              'draft' | 'needs_review'
}

